th: 0;\n}\n.pet-modes__label {\n  flex: none;\n  font-size: var(--pet-font-size-xs);\n  font-weight: var(--pet-font-weight-semibold);\n  color: var(--pet-color-text-faint);\n}\n.pet-modes__chips {\n  display: flex;\n  flex-wrap: wrap;\n  gap: var(--pet-space-xs);\n  flex: 1;\n  min-width: 0;\n}\n</style>\n"],"sourceRoot":""}]);
